// Construit un brief structuré pour Claude à partir des 3 appels précédents.
// L'objectif : un payload concis (<8 KB) qui décrit avant/après + le détail
// du rapprochement, prêt à être envoyé à Claude pour produire un rapport FR.

const params = $('Paramètres OCC').first().json;
const pre = $('Audit (pré-rapprochement)').first().json;
const rap = $('Rapprocher (intelligent)').first().json;
const post = $('Audit (post-rapprochement)').first().json;

function trimAudit(a) {
  if (!a) return null;
  return {
    societe: a.societe,
    comptes_bancaires: (a.comptes_bancaires || []).map(c => ({
      banque: c.banque,
      numero_compte: c.numero_compte,
      devise: c.devise,
      compte_comptable: c.compte_comptable,
      solde_actuel: c.solde_actuel,
      solde_dernier_releve: c.solde_dernier_releve,
      date_dernier_releve: c.date_dernier_releve,
    })),
    releves: a.releves,
    transactions: {
      total: a.transactions?.total,
      rapprochees: a.transactions?.rapprochees,
      classifiees_seulement: a.transactions?.classifiees_seulement,
      orphelines: a.transactions?.orphelines,
      taux_rapprochement_pct: a.transactions?.taux_rapprochement_pct,
      // Garde un échantillon pour Claude
      orphelines_echantillon: (a.transactions?.orphelines_echantillon || []).slice(0, 15),
    },
    factures: {
      total: a.factures?.total,
      par_statut: a.factures?.par_statut,
      impayees: a.factures?.impayees,
      impayees_montant_mur: a.factures?.impayees_montant_mur,
      impayees_echantillon: (a.factures?.impayees_echantillon || []).slice(0, 15),
    },
    plan_comptable_top: (a.plan_comptable_utilisation || []).slice(0, 10),
  };
}

const diff = {
  taux_rapprochement_pre_pct: pre?.transactions?.taux_rapprochement_pct ?? null,
  taux_rapprochement_post_pct: post?.transactions?.taux_rapprochement_pct ?? null,
  delta_rapprochees: (post?.transactions?.rapprochees ?? 0) - (pre?.transactions?.rapprochees ?? 0),
  delta_orphelines: (post?.transactions?.orphelines ?? 0) - (pre?.transactions?.orphelines ?? 0),
};

const brief = {
  societe: { id: params.societe_id, nom: params.societe_nom },
  generated_at: new Date().toISOString(),
  pre: trimAudit(pre),
  post: trimAudit(post),
  diff,
  rapprochement: {
    stats: rap?.stats,
    period: rap?.period,
    fx_rates_used: rap?.fx_rates_used,
    writes: rap?.writes,
    matches: (rap?.matches || []).slice(0, 30).map(m => ({
      tx: m.transactionKey,
      libelle: m.transaction?.libelle,
      debit: m.transaction?.debit,
      credit: m.transaction?.credit,
      devise: m.transaction?.devise,
      strategy: m.strategy,
      confidence: m.confidence,
      reasoning: m.reasoning,
      facture_ids: m.factureIds,
      amount_diff: m.amountDiff,
    })),
    classifications: (rap?.classifications || []).slice(0, 30),
  },
};

return { json: brief };
